// Import necessary libraries
import React, { useEffect } from 'react';
import { AsyncStorage } from 'react-native';

// Create a logger for network requests
const logNetworkRequests = async () => {
  const originalFetch = fetch;
  fetch = async (...args) => {
    console.log('Network Request:', args);
    const response = await originalFetch(...args);
    console.log('Network Response:', response);
    return response;
  };
};

// Create a logger for AsyncStorage operations
const logAsyncStorageOperations = async () => {
  const originalSetItem = AsyncStorage.setItem;
  AsyncStorage.setItem = async (key, value) => {
    console.debug('AsyncStorage Set Item:', key, value);
    return originalSetItem(key, value);
  };

  const originalGetItem = AsyncStorage.getItem;
  AsyncStorage.getItem = async (key) => {
    const value = await originalGetItem(key);
    console.debug('AsyncStorage Get Item:', key, value);
    return value;
  };

  const originalRemoveItem = AsyncStorage.removeItem;
  AsyncStorage.removeItem = async (key) => {
    console.debug('AsyncStorage Remove Item:', key);
    return originalRemoveItem(key);
  };
};

// Create a logger for user actions
const logUserActions = (action) => {
  console.log('User Action:', action);
};

// Create a logger for state changes
const logStateChanges = (prevState, nextState) => {
  console.debug('State Change:', { prevState, nextState });
};

// Initialize the comprehensive logger
const useDebugLogger = (appState, dispatch) => {
  useEffect(() => {
    logNetworkRequests();
    logAsyncStorageOperations();
  }, []);

  // Example usage for debugging user actions
  const handleUserAction = (action) => {
    logUserActions(action);
    dispatch(action);
  };

  // Example usage for debugging state changes
  useEffect(() => {
    if (appState !== null) {
      const nextAppState = { ...appState, /* any state updates */ };
      logStateChanges(appState, nextAppState);
    }
  }, [appState]);

  return { handleUserAction };
};

export default useDebugLogger;

